+            guard.cols,
+            guard.rows,
+            guard.tick_ms,
+            guard.seed,
+            total_p50 as f64 / 1000.0,
+            total_p95 as f64 / 1000.0,
+            total_p99 as f64 / 1000.0,
+            update_p50 as f64 / 1000.0,
+            update_p95 as f64 / 1000.0,
+            update_p99 as f64 / 1000.0,
+            render_p50 as f64 / 1000.0,
+            render_p95 as f64 / 1000.0,
