+            diff_p99 as f64 / 1000.0,
+            present_p50 as f64 / 1000.0,
+            present_p95 as f64 / 1000.0,
+            present_p99 as f64 / 1000.0,
+            top_p95 as f64 / 1000.0,
+            top_p99 as f64 / 1000.0
+        );
+        let _ = writeln!(guard.writer, "{line}");
+        let _ = guard.writer.flush();
+    }
+}
